// components/fields/Phone.tsx

import React from 'react';
import type {FieldValues} from 'react-hook-form';

import type {IPhone, UseFieldLogicElementProps} from '@lmb-it/kitsconcerto-types';
import {KitsPhoneComponent} from "../../../../_compat";

/**
 * Renders a phone number input with auto-detected country flag.
 * Value is an E.164 string (e.g., "+15551234567").
 */
export const Phone = <T extends FieldValues>({
                                                 element,
                                                 control,
                                                 getValues,
                                                 fieldLogic,
                                             }: UseFieldLogicElementProps<T>) => {

    const {
        field,
        fieldState,
        label,
        isDisabled,
        isRequired,
        helperText,
        hideError,
        leftAddon,
        rightAddon,
        attached,
        style: elementStyle,
        slots,
    } = fieldLogic

    const phoneElement = element as IPhone<T>;
    const {
        isWithCountryCode,
        defaultCountry,
        outputFormat,
        customCountriesCodesList,
        excludedCountries,
        includedCountries,
        withMask,
    } = phoneElement;

    return (
        <KitsPhoneComponent
            id={element.id.toString()}
            excludedCountries={excludedCountries}
            includedCountries={includedCountries}
            customCountriesCodesList={customCountriesCodesList}
            label={label}
            leftAddon={leftAddon}
            rightAddon={rightAddon}
            hideError={element.hideError}
            isWithCountryCode={isWithCountryCode}
            defaultCountry={defaultCountry}
            outputFormat={outputFormat}
            disabled={isDisabled}
            required={isRequired}
            errors={fieldState.error?.message}
            invalid={fieldState.invalid}
            attached={attached}
            style={elementStyle?.input}
            containerStyle={elementStyle?.container}
            slots={slots}
            onChange={(value) => {
                field.onChange({target: {value}})
            }}
            value={field.value}
        />
    );
};

export default Phone;
